import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Paths;

public class SecurePathTraversal {
    public static void main(String[] args) {
        String userInput = "../etc/passwd"; // User input containing a path traversal attack

        // Validate and sanitize user input to prevent directory traversal attacks
        String sanitizedInput = userInput.replaceAll("[^a-zA-Z0-9.-]", ""); // Remove any characters that are not alphanumeric or period/hyphen

        String baseDirectory = "/data/files/";

        // Combine the base directory with the sanitized user input using Paths.get()
        File file = Paths.get(baseDirectory, sanitizedInput).toFile();

        try (FileInputStream fis = new FileInputStream(file)) {
            int content;
            while ((content = fis.read()) != -1) {
                System.out.print((char) content);
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

